def normalize_search_terms(query: str) -> List[str]:
    terms = [t.strip() for t in re.split(r"\s+", query or "") if t.strip()]
    return terms[:10]


def build_search_sql(
    terms: List[str],
    fields: List[str],
    limit: int,
    offset: int,
) -> Tuple[str, Dict[str, Any]]:
    where_clauses = []
    params: Dict[str, Any] = {"limit": limit, "offset": offset}

    for i, term in enumerate(terms):
        term_param = f"term_{i}"
        params[term_param] = f"%{term}%"
        field_clauses = []
        for j, field in enumerate(fields):
            field_clauses.append(f"{field} ILIKE :{term_param}")
        where_clauses.append("(" + " OR ".join(field_clauses) + ")")

    where_sql = " AND ".join(where_clauses) if where_clauses else "TRUE"

    sql = f"""
        SELECT id, title, description
        FROM items
        WHERE {where_sql}
        ORDER BY id DESC
        LIMIT :limit
        OFFSET :offset
    """
